  "inlineSchema": "// prisma/schema.prisma\n// Ejecutar: npx prisma migrate dev --name add_menu_config_models\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// ── Roles y permisos ──────────────────────────────────────────────────────────\nmodel Role {\n  id              String   @id // slug: \"admin\", \"cashier\"\n  label           String\n  color           String   @default(\"blue\")\n  allowedViews    String[] // [\"pos\",\"orders\",\"account\"]\n  requiresCashCut Boolean  @default(false)\n  createdAt       DateTime @default(now())\n\n  users User[]\n}\n\nmodel User {\n  id        Int      @id @default(autoincrement())\n  name      String\n  email     String?  @unique\n  phone     String?\n  password  String // hash bcrypt\n  active    Boolean  @default(true)\n  roleId    String\n  role      Role     @relation(fields: [roleId], references: [id])\n  createdAt DateTime @default(now())\n\n  sales    Sale[]\n  cashCuts CashCut[]\n}\n\n// ── Catálogo de productos ─────────────────────────────────────────────────────\nmodel Category {\n  id       String @id // \"hot\", \"cold\", \"food\"\n  name     String\n  icon     String @default(\"☕\")\n  position Int    @default(0)\n\n  products Product[]\n}\n\nmodel Product {\n  id         Int      @id @default(autoincrement())\n  name       String\n  price      Float\n  image      String   @default(\"☕\")\n  active     Boolean  @default(true)\n  categoryId String\n  category   Category @relation(fields: [categoryId], references: [id])\n  createdAt  DateTime @default(now())\n\n  // Modificadores aplicables a este producto (relación many-to-many)\n  modifierGroups ProductModifierGroup[]\n  recipe         RecipeIngredient[]\n  orderItems     OrderItem[]\n}\n\n// ── Sistema de Modificadores Dinámicos ───────────────────────────────────────\n// Un \"ModifierGroup\" es una categoría de personalización: Tamaño, Leche,\n// Endulzante, Temperatura, Cobertura, etc.\n// Se crea desde la pantalla de Configuración de Menú y se puede asignar\n// a uno o varios productos.\n\nmodel ModifierGroup {\n  id        Int      @id @default(autoincrement())\n  name      String // \"Tamaño\", \"Endulzante\"\n  inputType String   @default(\"single\") // \"single\" | \"multi\"\n  required  Boolean  @default(false)\n  position  Int      @default(0)\n  color     String   @default(\"amber\") // badge color: amber, blue, green, violet, rose, cyan, orange, indigo\n  appliesTo String[] @default([]) // IDs de categorías donde aplica. Vacío = todas\n  kind      String   @default(\"custom\") // \"size\" | \"milk\" | \"extra\" | \"custom\"\n  createdAt DateTime @default(now())\n\n  options  ModifierOption[]\n  products ProductModifierGroup[]\n}\n\nmodel ModifierOption {\n  id         Int           @id @default(autoincrement())\n  name       String // \"Grande\", \"Stevia\"\n  extraPrice Float         @default(0)\n  position   Int           @default(0)\n  groupId    Int\n  group      ModifierGroup @relation(fields: [groupId], references: [id], onDelete: Cascade)\n\n  // Referencia opcional a inventario (para descontar automáticamente)\n  inventoryItemId Int?\n  inventoryItem   InventoryItem? @relation(fields: [inventoryItemId], references: [id])\n\n  orderItemModifiers OrderItemModifier[]\n}\n\n// Tabla pivote: qué grupos de modificadores tiene cada producto\nmodel ProductModifierGroup {\n  productId       Int\n  modifierGroupId Int\n  product         Product       @relation(fields: [productId], references: [id], onDelete: Cascade)\n  modifierGroup   ModifierGroup @relation(fields: [modifierGroupId], references: [id], onDelete: Cascade)\n\n  @@id([productId, modifierGroupId])\n}\n\n// ── Inventario ────────────────────────────────────────────────────────────────\nmodel InventoryItem {\n  id            Int       @id @default(autoincrement())\n  name          String\n  quantity      Float\n  unit          String // \"g\", \"ml\", \"pz\"\n  minStock      Float     @default(0)\n  lastRestocked DateTime?\n  updatedAt     DateTime  @updatedAt\n\n  recipe          RecipeIngredient[]\n  modifierOptions ModifierOption[]\n}\n\nmodel RecipeIngredient {\n  id              Int     @id @default(autoincrement())\n  productId       Int\n  inventoryItemId Int\n  quantity        Float\n  unit            String?\n\n  product       Product       @relation(fields: [productId], references: [id], onDelete: Cascade)\n  inventoryItem InventoryItem @relation(fields: [inventoryItemId], references: [id])\n\n  @@unique([productId, inventoryItemId])\n}\n\n// ── Ventas ────────────────────────────────────────────────────────────────────\nmodel Sale {\n  id            Int      @id @default(autoincrement())\n  orderNumber   Int      @unique @default(autoincrement())\n  date          DateTime @default(now())\n  subtotal      Float\n  tax           Float\n  total         Float\n  customerName  String?\n  customerEmail String?\n  emailSent     Boolean  @default(false) // ← si ya se envió el ticket\n  userId        Int\n  user          User     @relation(fields: [userId], references: [id])\n\n  items OrderItem[]\n}\n\nmodel OrderItem {\n  id        Int     @id @default(autoincrement())\n  quantity  Int\n  unitPrice Float\n  subtotal  Float\n  saleId    Int\n  productId Int\n  sale      Sale    @relation(fields: [saleId], references: [id], onDelete: Cascade)\n  product   Product @relation(fields: [productId], references: [id])\n\n  // Modificadores seleccionados para este ítem\n  modifiers OrderItemModifier[]\n}\n\nmodel OrderItemModifier {\n  id               Int            @id @default(autoincrement())\n  orderItemId      Int\n  modifierOptionId Int\n  orderItem        OrderItem      @relation(fields: [orderItemId], references: [id], onDelete: Cascade)\n  modifierOption   ModifierOption @relation(fields: [modifierOptionId], references: [id])\n}\n\n// ── Cortes de caja ────────────────────────────────────────────────────────────\nmodel CashCut {\n  id           Int      @id @default(autoincrement())\n  date         DateTime @default(now())\n  loginTime    DateTime\n  salesCount   Int\n  totalSales   Float\n  expectedCash Float\n  actualCash   Float\n  difference   Float\n  notes        String?\n  userId       Int\n  user         User     @relation(fields: [userId], references: [id])\n}\n",
  "inlineSchemaHash": "93f8a2aea33e987c2f587607aaf1d0f0ab7563835c8ebc029cb2619d619bf19f",
